 31→                        {{ $t('t0712', { number: inputNumbers }) }}
 32→                    </div>
 33→                    <div key="3" class="iconBtn group-fade-item">
 34→                        <el-button type="primary" size="small" @click="onSearch">
 35→                            <span class="el-icon-search"> {{ $t('search') }} </span>
 36→                        </el-button>
 37→                    </div>
 38→                </transition-group>
 39→                <div v-for="item in 4" :key="item" class="empty-block searchItem"></div>
 40→            </div>
 41→        </div>
 42→        <div class="searchMore">
 43→            <!--            v-show="showSearchMore"-->
 44→            <HrmgtSearchMore
 45→                :able-show="showSearchMore"
 46→                :input-filters="inputFilters"
 47→                :options="hideOptions"
 48→                :value="hideInputFilters"
 49→                :saved-filters="savedFilters"
 50→                @selectSaveFilter="selectSaveFilter"
 51→                @deleteItem="deleteSaveFilter"
 52→                @hideEl="hideSearchMore"
 53→                @change="changeConditions"
 54→                @reset="clearFilters"
 55→                @add="saveFilters"
 56→                @deleteSelect="deleteSelect"
 57→                @deleteSaveFilter="deleteSaveFilter"
 58→            />
 59→        </div>
 60→
 61→        <el-dialog
 62→            :visible.sync="showSavePanel"
 63→            :destroy-on-close="true"
 64→            :show-close="true"
 65→            :modal="false"
 66→            :title="$t('t1480')"
 67→            :width="'450px'"
 68→            :custom-class="'elDialog'"
 69→            :append-to-body="true"
 70→            :fullscreen="false"
 71→        >
 72→            <template #default>
 73→                <div>
 74→                    <span> {{ $t('t0659') }}： </span>
 75→                    <el-input v-model="filtername" class="filenameInput" />
 76→                </div>
 77→            </template>
 78→            <template #footer>
 79→                <el-button size="medium" @click="showSavePanel = false">{{ $t('cancel') }}</el-button>
 80→                <el-button size="medium" type="primary" @click="confirmSaveFilters">{{ $t('confirm') }}</el-button>
 81→            </template>
 82→        </el-dialog>
 83→    </div>
 84→</template>
 85→
 86→<script lang="ts">
 87→import deepCopy from 'deep-copy'
 88→
 89→import { getMERGEABLE_FIELD } from '@/Macro'
 90→
 91→import { showMessageInfo } from '../../utils'
 92→import EbButton from '../EbButton'
 93→import EbDialog from '../EbDialog'
 94→
 95→import HrmgtSearchItem from './HrmgtSearchItem.vue'
 96→import HrmgtSearchMore from './HrmgtSearchMore'
 97→// import { SFUserMap2} from '@/common/MDictionary'
 98→export default {
 99→    name: 'HrmgtSearchBar',
100→
101→    components: {
102→        EbButton,
103→        EbDialog,
104→        HrmgtSearchMore,
105→        HrmgtSearchItem,
106→    },
107→
108→    props: {
109→        options: { type: Array, default: () => [] },
110→        autoSearch: { type: Boolean, default: false },
111→        defaultFilters: { type: Array, default: () => [] },
112→        saveKey: { type: String, default: '' },
113→    },
114→
115→    data() {
116→        return {
117→            showSearchMore: false,
118→            // 搜索条件
119→            inputFilters: [],
120→            // 搜索框中的输入值
121→            searchBoxsValues: [],
122→            // 姓名，花名 直接列出，其他筛选项隐藏
123→            showOptions: [],
124→            showInputFilters: [],
125→            hideOptions: [],
126→            hideInputFilters: [],
127→            // 选中条件个数
128→            inputNumbers: 0,
129→
130→            inputValue: '',
131→            showSavePanel: false,
132→            filtername: '',
133→            savedFilters: [],
134→        }
135→    },
136→
137→    watch: {
138→        defaultFilters: {
139→            immediate: true,
140→            handler(vals) {
141→                // 没有选项时直接返回
142→                if (this.options.length === 0) {
143→                    return
144→                }
145→
146→                this.inputFilters = []
147→                for (const v of deepCopy(vals)) {
148→                    this.inputFilters.push({
149→                        ...v,
150→                        visible: false,
151→                    })
152→                }
153→            },
154→        },
155→
156→        inputFilters: {
157→            immediate: true,
158→            deep: true,
159→            handler(vals) {
160→                // 非受控组件，直接传出值就行
161→                const rst = vals.map(({ value, param }) => ({ key: value, param }))
162→                this.$emit('change', rst)
163→                this.searchBoxsValues = deepCopy(this.inputFilters)
164→                this.inputNumbers = vals.length
165→            },
166→        },
167→
168→        searchBoxsValues: {
169→            immediate: true,
170→            deep: true,
171→            handler(vals) {
172→                // 姓名，花名，以及手动设置outside的默认展示，不隐藏(oa端需要隐藏nickname，加上isOutside判断)
173→                this.showInputFilters = vals.filter(
174→                    item => (['nickname', 'username'].includes(item.value) && item.isOutside !== false) || item.isOutside,
175→                )
176→                this.hideInputFilters = vals.filter(
177→                    item => !(['nickname', 'username'].includes(item.value) && item.isOutside !== false) && !item.isOutside,
178→                )
179→            },
180→        },
181→
182→        options: {
183→            immediate: true,
184→            deep: true,
185→            handler(val: any[]) {
186→                // 展示项
187→                this.showOptions = val.filter(item => ['nickname', 'username'].includes(item?.value) || item?.isOutside)
188→                this.hideOptions = val.filter(item => !(['nickname', 'username'].includes(item?.value) || item?.isOutside))
189→            },
190→        },
191→    },
192→
193→    mounted() {
194→        this.savedFilters = JSON.parse(window.localStorage.getItem(this.saveKey) || '[]')
195→    },
196→
197→    methods: {
198→        getDATA() {
199→            return this.searchBoxsValues[0].isOutside
200→        },
201→
202→        hideSearchMore() {
203→            this.showSearchMore = false
204→        },
205→
206→        onSearch() {
207→            this.inputFilters = deepCopy(this.searchBoxsValues)
208→            this.showSearchMore = false
209→            this.$emit('search')
210→
211→            // workforce-management 组件使用搜索，直接传参
212→            this.$emit('addParamsSearch', this.getValue())
213→        },
214→
215→        clearFilters() {
216→            this.inputFilters = []
217→            this.searchBoxsValues = deepCopy(this.inputFilters)
218→            if (this.autoSearch) {
219→                this.onSearch()
220→            }
221→        },
222→
223→        saveFilters() {
224→            this.showSavePanel = true
225→        },
226→
227→        confirmSaveFilters() {
228→            const index = this.savedFilters.findIndex(el => el.name === this.filtername)
229→            if (index === -1) {
230→                this.savedFilters.push({ name: this.filtername, filters: this.inputFilters })
231→            } else {
232→                this.savedFilters[index].filters = this.inputFilters
233→            }
234→            window.localStorage.setItem(this.saveKey, JSON.stringify(this.savedFilters))
235→            this.showSavePanel = false
236→        },
237→
238→        deleteSaveFilter(item) {
239→            this.savedFilters = this.savedFilters.filter(el => el.name !== item.name)
240→            window.localStorage.setItem(this.saveKey, JSON.stringify(this.savedFilters))
241→        },
242→
243→        selectSaveFilter(values) {
244→            this.inputFilters = JSON.parse(JSON.stringify(values))
245→            this.searchBoxsValues = deepCopy(this.inputFilters)
246→            if (this.autoSearch) {
247→                this.onSearch()
248→            }
249→        },
250→
251→        getValue<T extends string>(): { key: T; param: number | string | boolean | any[] | undefined; isOutside: boolean }[] {
252→            return this.inputFilters.map(({ value, param, isOutside, display, multiple }) => {
253→                // 新增判断，如果组件display 是 自动提示（autoCompleteInput） 并且 支持 多选（multiple）的情况下，重新组合参数
254→                if (getMERGEABLE_FIELD().field.has(value) || (display === 'autoCompleteInput' && multiple) || display === 'multipleInput') {
255→                    param = param.safeTrim().split(getMERGEABLE_FIELD().separator)
256→                }
257→                if (new Set(['inputer', 'staff_inputer']).has(value)) {
258→                    console.log('param =', param)
259→                    param = param
260→                        .map(a => {
261→                            // if (a.safeTrim() === '公开') return -1
262→                            if (['公开', 'Public', 'public'].includes(a.safeTrim())) {
263→                                return -1
264→                            }
265→                            const t = this.$store.state.options.hrList.find(ele => ele.label.safeTrim() === a.safeTrim())
266→                            return t ? t.value : ''
267→                        })
268→                        .filter(a => a)
269→                    if (param.length === 0) {
270→                        showMessageInfo(`${this.$t('t1481')}`)
271→                    }
272→                }
273→                return { key: value, param, isOutside }
274→            })
275→        },
276→
277→        getObjectVal<T extends string>(): Record<T, number | string | boolean | any[] | undefined> {
278→            const result: Record<string, any> = {}
279→            this.getValue().forEach(o => (result[o.key] = o.param))
280→            return result
281→        },
282→
283→        changeConditions({ item, param }) {
284→            const index = this.searchBoxsValues.findIndex(el => el.value === item.value),
285→                targetItem = { value: item.value, visible: false, param, isOutside: item.isOutside, display: item.display, multiple: item.multiple }
286→            if (index >= 0) {
287→                this.searchBoxsValues.splice(index, 1, targetItem)
288→            } else {
289→                this.searchBoxsValues.push(targetItem)
290→            }
291→            this.inputFilters = deepCopy(this.searchBoxsValues)
292→        },
293→
294→        deleteSelect(item) {
295→            const index = this.searchBoxsValues.findIndex(el => el.value === item.value)
296→            index !== -1 && this.searchBoxsValues.splice(index, 1)
297→            this.inputFilters = deepCopy(this.searchBoxsValues)
298→        },
299→    },
